/* =========================================================
   HOUSEKEEPING REPORT – DESIGN SYSTEM
   Elderly-friendly · Mobile-first · Hotel Blue
   ========================================================= */

/* ── Reset & Root ── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

:root {
  /* Colors */
  --color-primary:    #4A90FF;
  --color-primary-dk: #3575e0;
  --color-primary-lt: #E8F4FF;
  --color-disabled:   #B0C4DE;
  --color-bg:         #F8F9FB;
  --color-white:      #FFFFFF;
  --color-text:       #111111;
  --color-text-body:  #333333;
  --color-caption:    #6B7280;
  --color-success:    #22C55E;
  --color-error:      #EF4444;
  --color-border:     #E2E8F0;

  /* Shadows */
  --shadow-card:   0 8px 24px rgba(74,144,255,0.15);
  --shadow-btn:    0 4px 16px rgba(74,144,255,0.35);
  --shadow-sm:     0 2px 8px rgba(0,0,0,0.08);

  /* Typography */
  --font:          'Nunito', sans-serif;

  /* Spacing */
  --px: 16px;
  --gap: 24px;
  --card-gap: 16px;
}

html, body {
  font-family: var(--font);
  background: var(--color-bg);
  color: var(--color-text-body);
  min-height: 100dvh;
  height: 100%;
  overflow: hidden; /* screens handle own scroll */
}

/* ── Screen System ── */
.screen {
  position: fixed;
  inset: 0;
  background: linear-gradient(160deg, #F8F9FB 0%, #FFFFFF 100%);
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  transform: translateX(40px);
  transition: opacity 0.28s ease, transform 0.28s ease;
  z-index: 1;
}

.screen--active {
  opacity: 1;
  pointer-events: all;
  transform: translateX(0);
  z-index: 2;
}

.screen--exit {
  opacity: 0;
  transform: translateX(-40px);
  pointer-events: none;
}

.screen__inner {
  display: flex;
  flex-direction: column;
  height: 100%;
  max-width: 480px;
  margin: 0 auto;
  width: 100%;
}

.screen__inner--scroll {
  overflow-y: auto;
  overflow-x: hidden;
  -webkit-overflow-scrolling: touch;
}

.screen__inner--center {
  justify-content: center;
  align-items: center;
  padding: var(--px);
  text-align: center;
}

/* ── App Logo ── */
.app-logo {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 20px var(--px) 0;
}

.app-logo__icon {
  font-size: 28px;
  line-height: 1;
}

.app-logo__name {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-primary);
  text-transform: uppercase;
  letter-spacing: 1.5px;
}

/* ── Screen Header ── */
.screen__top {
  padding: 0;
  flex-shrink: 0;
}

.screen__top--dark {
  background: #0a1628;
}

.screen__title {
  font-size: 28px;
  font-weight: 900;
  color: var(--color-text);
  padding: 12px var(--px) 4px;
  line-height: 1.2;
}

.screen__subtitle {
  font-size: 15px;
  font-weight: 400;
  color: var(--color-caption);
  padding: 0 var(--px) 20px;
  line-height: 1.5;
}

.screen-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px var(--px);
  gap: 12px;
}

.screen__top--dark .screen-header {
  padding-top: max(14px, env(safe-area-inset-top));
}

.screen-header__info {
  flex: 1;
  text-align: center;
}

.room-badge {
  display: inline-block;
  background: var(--color-primary);
  color: white;
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 0.5px;
  padding: 4px 16px;
  border-radius: 100px;
}

.screen__top--dark .room-badge {
  background: rgba(74,144,255,0.25);
  color: #7ab8ff;
  border: 1px solid rgba(74,144,255,0.4);
}

.screen-header__sub {
  font-size: 12px;
  color: var(--color-caption);
  margin-top: 4px;
  font-weight: 600;
}

.screen__top--dark .screen-header__sub {
  color: #7ab8ff88;
}

.photo-counter {
  font-size: 16px;
  font-weight: 800;
  color: var(--color-primary);
  background: var(--color-primary-lt);
  padding: 4px 12px;
  border-radius: 100px;
  min-width: 52px;
  text-align: center;
}

.screen__top--dark .photo-counter {
  background: rgba(74,144,255,0.15);
  color: #7ab8ff;
}

/* ── Back Button ── */
.btn-back {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--color-white);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: var(--shadow-sm);
  color: var(--color-text);
  flex-shrink: 0;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
}

.screen__top--dark .btn-back {
  background: rgba(255,255,255,0.12);
  color: white;
  box-shadow: none;
}

.btn-back:active {
  transform: scale(0.94);
}

/* ── Screen Body ── */
.screen__body {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.screen__body--padded {
  padding: var(--gap) var(--px);
  gap: var(--gap);
  justify-content: flex-start;
}

/* ── Screen Footer ── */
.screen__footer {
  padding: var(--card-gap) var(--px);
  padding-bottom: max(var(--card-gap), env(safe-area-inset-bottom));
  flex-shrink: 0;
}

.screen__footer--sticky {
  position: sticky;
  bottom: 0;
  background: linear-gradient(to top, #fff 80%, transparent);
  padding-top: 20px;
}

/* ── Room Input ── */
.input-card {
  padding: 0 var(--px);
}

.room-input {
  width: 100%;
  height: 72px;
  background: var(--color-primary-lt);
  border: 2.5px solid transparent;
  border-radius: 20px;
  font-family: var(--font);
  font-size: 32px;
  font-weight: 800;
  color: var(--color-text);
  text-align: center;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
  letter-spacing: 2px;
}

.room-input::placeholder {
  color: #b0c4de;
  font-weight: 600;
  font-size: 24px;
}

.room-input:focus {
  border-color: var(--color-primary);
  box-shadow: 0 0 0 4px rgba(74,144,255,0.15);
}

/* ── Buttons ── */
.btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: 100%;
  height: 56px;
  border: none;
  border-radius: 28px;
  font-family: var(--font);
  font-size: 17px;
  font-weight: 800;
  cursor: pointer;
  transition: transform 0.12s ease, box-shadow 0.12s ease, background 0.12s ease;
  letter-spacing: 0.3px;
  user-select: none;
}

.btn--primary {
  background: var(--color-primary);
  color: white;
  box-shadow: var(--shadow-btn);
}

.btn--primary:not(.btn--disabled):active {
  transform: scale(0.97);
  background: var(--color-primary-dk);
  box-shadow: 0 2px 8px rgba(74,144,255,0.25);
}

.btn--disabled {
  background: var(--color-disabled) !important;
  box-shadow: none !important;
  cursor: not-allowed;
  opacity: 0.75;
}

.btn--camera-next {
  margin: 0 var(--px);
  width: calc(100% - 32px);
}

/* ── Camera ── */
.camera-view-wrap {
  flex: 1;
  position: relative;
  background: #0a1628;
  overflow: hidden;
}

.camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.camera-canvas {
  display: none;
}

.camera-overlay {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: rgba(10,22,40,0.85);
  gap: 12px;
  transition: opacity 0.3s ease;
}

.camera-overlay--hidden {
  opacity: 0;
  pointer-events: none;
}

.camera-overlay__icon {
  font-size: 48px;
}

.camera-overlay__text {
  font-size: 15px;
  font-weight: 600;
  color: rgba(255,255,255,0.7);
}

.camera-controls {
  background: #0a1628;
  padding: 12px 0 max(12px, env(safe-area-inset-bottom));
  flex-shrink: 0;
}

/* Thumbnails */
.thumbnail-row {
  display: flex;
  gap: 8px;
  padding: 0 var(--px) 12px;
  min-height: 68px;
  align-items: center;
  overflow-x: auto;
  scrollbar-width: none;
}

.thumbnail-row::-webkit-scrollbar { display: none; }

.thumbnail {
  position: relative;
  flex-shrink: 0;
  width: 60px;
  height: 60px;
  border-radius: 12px;
  overflow: hidden;
  border: 2px solid rgba(74,144,255,0.5);
}

.thumbnail img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.thumbnail__delete {
  position: absolute;
  top: 2px;
  right: 2px;
  width: 20px;
  height: 20px;
  border-radius: 50%;
  background: rgba(0,0,0,0.7);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  font-size: 11px;
  line-height: 1;
  padding: 0;
}

/* Shutter */
.shutter-row {
  display: flex;
  justify-content: center;
  padding: 0 0 10px;
}

.shutter-btn {
  position: relative;
  width: 72px;
  height: 72px;
  border-radius: 50%;
  background: transparent;
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.1s ease;
}

.shutter-btn:active {
  transform: scale(0.93);
}

.shutter-btn__ring {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 3px solid white;
}

.shutter-btn__inner {
  width: 58px;
  height: 58px;
  border-radius: 50%;
  background: white;
  transition: background 0.1s ease;
}

.shutter-btn:active .shutter-btn__inner {
  background: #d0d8e4;
}

.camera-hint {
  text-align: center;
  font-size: 12px;
  font-weight: 600;
  color: rgba(255,255,255,0.45);
  padding: 0 var(--px) 10px;
}

/* ── Report Screen ── */
.report-section {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.section-label {
  font-size: 13px;
  font-weight: 800;
  color: var(--color-primary);
  text-transform: uppercase;
  letter-spacing: 1px;
}

/* Report Photos */
.report-photos {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  scrollbar-width: none;
  padding-bottom: 4px;
}

.report-photos::-webkit-scrollbar { display: none; }

.report-photo {
  flex-shrink: 0;
  width: 88px;
  height: 88px;
  border-radius: 16px;
  overflow: hidden;
  border: 2px solid var(--color-primary-lt);
  box-shadow: var(--shadow-sm);
}

.report-photo img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

/* Voice Card */
.voice-card {
  background: var(--color-white);
  border-radius: 20px;
  box-shadow: var(--shadow-card);
  padding: 20px 16px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 16px;
}

.mic-btn {
  position: relative;
  width: 80px;
  height: 80px;
  border-radius: 50%;
  background: var(--color-primary-lt);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.2s ease, transform 0.1s ease, box-shadow 0.2s ease;
  color: var(--color-primary);
}

.mic-btn:active {
  transform: scale(0.95);
}

.mic-btn--recording {
  background: #fee2e2;
  color: var(--color-error);
  box-shadow: 0 0 0 0 rgba(239,68,68,0.4);
  animation: pulse-mic 1.4s ease infinite;
}

@keyframes pulse-mic {
  0%   { box-shadow: 0 0 0 0 rgba(239,68,68,0.35); }
  70%  { box-shadow: 0 0 0 20px rgba(239,68,68,0); }
  100% { box-shadow: 0 0 0 0 rgba(239,68,68,0); }
}

.mic-btn__ripple {
  position: absolute;
  inset: -8px;
  border-radius: 50%;
  opacity: 0;
  pointer-events: none;
}

.mic-icon {
  width: 36px;
  height: 36px;
  position: relative;
  z-index: 1;
}

.mic-status {
  font-size: 14px;
  font-weight: 700;
  color: var(--color-caption);
  text-align: center;
}

.mic-status--recording {
  color: var(--color-error);
  animation: blink 0.9s ease infinite;
}

@keyframes blink {
  0%, 100% { opacity: 1; }
  50%       { opacity: 0.4; }
}

.voice-text-wrap {
  width: 100%;
}

.voice-textarea {
  width: 100%;
  background: var(--color-bg);
  border: 2px solid var(--color-border);
  border-radius: 12px;
  font-family: var(--font);
  font-size: 15px;
  font-weight: 400;
  color: var(--color-text-body);
  padding: 12px;
  resize: none;
  outline: none;
  line-height: 1.6;
  transition: border-color 0.2s ease;
  min-height: 80px;
}

.voice-textarea:focus {
  border-color: var(--color-primary);
}

.voice-textarea::placeholder {
  color: #c0cdd8;
}

/* ── Success Screen ── */
.success-anim {
  margin-bottom: 28px;
}

.success-circle {
  width: 100px;
  height: 100px;
}

.success-check {
  width: 100px;
  height: 100px;
}

.success-check__circle {
  stroke: var(--color-success);
  stroke-width: 2;
  stroke-dasharray: 166;
  stroke-dashoffset: 166;
  stroke-linecap: round;
  animation: circle-draw 0.6s cubic-bezier(0.65, 0, 0.45, 1) 0.2s forwards;
}

.success-check__path {
  stroke: var(--color-success);
  stroke-width: 2.5;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-dasharray: 48;
  stroke-dashoffset: 48;
  animation: check-draw 0.4s cubic-bezier(0.65, 0, 0.45, 1) 0.7s forwards;
}

@keyframes circle-draw {
  to { stroke-dashoffset: 0; }
}

@keyframes check-draw {
  to { stroke-dashoffset: 0; }
}

.success-title {
  font-size: 28px;
  font-weight: 900;
  color: var(--color-text);
  line-height: 1.25;
  margin-bottom: 12px;
}

.success-subtitle {
  font-size: 17px;
  font-weight: 600;
  color: var(--color-primary);
  margin-bottom: 8px;
}

.success-meta {
  font-size: 13px;
  color: var(--color-caption);
  margin-bottom: 40px;
}

.btn--new {
  max-width: 320px;
}

/* ── Spinner ── */
.spinner {
  width: 22px;
  height: 22px;
  border: 3px solid rgba(255,255,255,0.4);
  border-top-color: white;
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

.spinner--hidden { display: none; }

@keyframes spin {
  to { transform: rotate(360deg); }
}

/* ── Toast ── */
.toast {
  background: #fee2e2;
  color: var(--color-error);
  font-size: 13px;
  font-weight: 700;
  padding: 10px 16px;
  border-radius: 12px;
  text-align: center;
  margin-bottom: 8px;
  animation: fade-in 0.2s ease;
}

.toast--hidden {
  display: none;
}

.global-toast {
  position: fixed;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%);
  background: #1e293b;
  color: white;
  font-family: var(--font);
  font-size: 14px;
  font-weight: 700;
  padding: 12px 24px;
  border-radius: 100px;
  z-index: 999;
  white-space: nowrap;
  box-shadow: 0 8px 24px rgba(0,0,0,0.2);
  animation: slide-up 0.25s ease;
}

.global-toast--hidden {
  display: none;
}

@keyframes slide-up {
  from { opacity: 0; transform: translateX(-50%) translateY(12px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}

@keyframes fade-in {
  from { opacity: 0; }
  to   { opacity: 1; }
}

/* ── Scrollbar ── */
.screen__body--padded::-webkit-scrollbar { display: none; }

/* =========================================================
   HOUSEKEEPING REPORT – DESIGN SYSTEM
   Elderly-friendly · Mobile-first · Hotel Blue
   Font: Nunito (warm, round, highly legible)
   ========================================================= */

/* ── Reset & Root ── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

:root {
  --color-primary:    #4A90FF;
  --color-primary-dk: #3575e0;
  --color-primary-lt: #E8F4FF;
  --color-disabled:   #B0C4DE;
  --color-bg:         #F8F9FB;
  --color-white:      #FFFFFF;
  --color-text:       #111111;
  --color-text-body:  #333333;
  --color-caption:    #6B7280;
  --color-success:    #22C55E;
  --color-error:      #EF4444;
  --color-border:     #E2E8F0;

  --shadow-card:   0 8px 24px rgba(74,144,255,0.15);
  --shadow-btn:    0 4px 16px rgba(74,144,255,0.35);
  --shadow-sm:     0 2px 8px rgba(0,0,0,0.08);

  --font: 'Nunito', sans-serif;
  --px: 16px;
  --gap: 24px;
  --card-gap: 16px;
}

html, body {
  font-family: var(--font);
  background: var(--color-bg);
  color: var(--color-text-body);
  min-height: 100dvh;
  height: 100%;
  overflow: hidden;
}

/* ── Screen System ── */
.screen {
  position: fixed;
  inset: 0;
  background: linear-gradient(160deg, #F8F9FB 0%, #FFFFFF 100%);
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  transform: translateX(40px);
  transition: opacity 0.28s ease, transform 0.28s ease;
  z-index: 1;
}

.screen--active {
  opacity: 1;
  pointer-events: all;
  transform: translateX(0);
  z-index: 2;
}

.screen--exit {
  opacity: 0;
  transform: translateX(-40px);
  pointer-events: none;
}

.screen__inner {
  display: flex;
  flex-direction: column;
  height: 100%;
  max-width: 480px;
  margin: 0 auto;
  width: 100%;
}

.screen__inner--scroll {
  overflow-y: auto;
  overflow-x: hidden;
  -webkit-overflow-scrolling: touch;
}

.screen__inner--center {
  justify-content: center;
  align-items: center;
  padding: var(--px);
  text-align: center;
}

/* ── App Logo ── */
.app-logo {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: max(20px, env(safe-area-inset-top)) var(--px) 0;
}

.app-logo__icon {
  font-size: 28px;
  line-height: 1;
}

.app-logo__name {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-primary);
  text-transform: uppercase;
  letter-spacing: 1.5px;
}

/* ── Screen Top ── */
.screen__top {
  flex-shrink: 0;
}

.screen__top--dark {
  background: #0a1628;
}

.screen__title {
  font-size: 28px;
  font-weight: 900;
  color: var(--color-text);
  padding: 12px var(--px) 4px;
  line-height: 1.2;
}

.screen__subtitle {
  font-size: 15px;
  color: var(--color-caption);
  padding: 0 var(--px) 20px;
  line-height: 1.5;
}

.screen-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px var(--px);
  gap: 12px;
}

.screen__top--dark .screen-header {
  padding-top: max(14px, env(safe-area-inset-top));
}

.screen-header__info {
  flex: 1;
  text-align: center;
}

.room-badge {
  display: inline-block;
  background: var(--color-primary);
  color: white;
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 0.5px;
  padding: 4px 16px;
  border-radius: 100px;
}

.screen__top--dark .room-badge {
  background: rgba(74,144,255,0.2);
  color: #7ab8ff;
  border: 1px solid rgba(74,144,255,0.35);
}

.screen-header__sub {
  font-size: 12px;
  color: var(--color-caption);
  margin-top: 4px;
  font-weight: 600;
}

.screen__top--dark .screen-header__sub {
  color: rgba(122,184,255,0.6);
}

.photo-counter {
  font-size: 16px;
  font-weight: 800;
  color: var(--color-primary);
  background: var(--color-primary-lt);
  padding: 4px 12px;
  border-radius: 100px;
  min-width: 52px;
  text-align: center;
}

.screen__top--dark .photo-counter {
  background: rgba(74,144,255,0.15);
  color: #7ab8ff;
}

/* ── Back Button ── */
.btn-back {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: var(--color-white);
  border: none;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: var(--shadow-sm);
  color: var(--color-text);
  flex-shrink: 0;
  transition: transform 0.15s ease;
}

.screen__top--dark .btn-back {
  background: rgba(255,255,255,0.1);
  color: white;
  box-shadow: none;
}

.btn-back:active { transform: scale(0.93); }

/* ── Screen Body ── */
.screen__body {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.screen__body--padded {
  padding: var(--gap) var(--px);
  gap: var(--gap);
  justify-content: flex-start;
}

/* ── Screen Footer ── */
.screen__footer {
  padding: var(--card-gap) var(--px);
  padding-bottom: max(var(--card-gap), env(safe-area-inset-bottom));
  flex-shrink: 0;
}

.screen__footer--sticky {
  position: sticky;
  bottom: 0;
  background: linear-gradient(to top, #fff 75%, transparent);
  padding-top: 20px;
}

/* ── Room Input ── */
.input-card {
  padding: 0 var(--px);
}

.room-input {
  width: 100%;
  height: 72px;
  background: var(--color-primary-lt);
  border: 2.5px solid transparent;
  border-radius: 20px;
  font-family: var(--font);
  font-size: 36px;
  font-weight: 800;
  color: var(--color-text);
  text-align: center;
  outline: none;
  letter-spacing: 3px;
  transition: border-color 0.2s ease, box-shadow 0.2s ease;
}

.room-input::placeholder {
  color: #b0c4de;
  font-weight: 600;
  font-size: 24px;
  letter-spacing: 1px;
}

.room-input:focus {
  border-color: var(--color-primary);
  box-shadow: 0 0 0 4px rgba(74,144,255,0.12);
}

