   Font: Nunito (warm, round, highly legible)
   ========================================================= */

/* ── Reset & Root ── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  -webkit-tap-highlight-color: transparent;
}

:root {
  --color-primary:    #4A90FF;
  --color-primary-dk: #3575e0;
  --color-primary-lt: #E8F4FF;
  --color-disabled:   #B0C4DE;
  --color-bg:         #F8F9FB;
  --color-white:      #FFFFFF;
  --color-text:       #111111;
  --color-text-body:  #333333;
  --color-caption:    #6B7280;
  --color-success:    #22C55E;
  --color-error:      #EF4444;
  --color-border:     #E2E8F0;

  --shadow-card:   0 8px 24px rgba(74,144,255,0.15);
  --shadow-btn:    0 4px 16px rgba(74,144,255,0.35);
  --shadow-sm:     0 2px 8px rgba(0,0,0,0.08);

  --font: 'Nunito', sans-serif;
  --px: 16px;
  --gap: 24px;
  --card-gap: 16px;
}

html, body {
  font-family: var(--font);
  background: var(--color-bg);
  color: var(--color-text-body);
  min-height: 100dvh;
  height: 100%;
  overflow: hidden;
}

/* ── Screen System ── */
.screen {
  position: fixed;
  inset: 0;
  background: linear-gradient(160deg, #F8F9FB 0%, #FFFFFF 100%);
  display: flex;
  flex-direction: column;
  opacity: 0;
  pointer-events: none;
  transform: translateX(40px);
  transition: opacity 0.28s ease, transform 0.28s ease;
  z-index: 1;
}

.screen--active {
  opacity: 1;
  pointer-events: all;
  transform: translateX(0);
  z-index: 2;
}

.screen--exit {
  opacity: 0;
  transform: translateX(-40px);
  pointer-events: none;
}

.screen__inner {
  display: flex;
  flex-direction: column;
  height: 100%;
  max-width: 480px;
  margin: 0 auto;
  width: 100%;
}

.screen__inner--scroll {
  overflow-y: auto;
  overflow-x: hidden;
  -webkit-overflow-scrolling: touch;
}

.screen__inner--center {
  justify-content: center;
  align-items: center;
  padding: var(--px);
  text-align: center;
}

/* ── App Logo ── */
.app-logo {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: max(20px, env(safe-area-inset-top)) var(--px) 0;
}

.app-logo__icon {
  font-size: 28px;
  line-height: 1;
}

.app-logo__name {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-primary);
  text-transform: uppercase;
  letter-spacing: 1.5px;
}

/* ── Screen Top ── */
.screen__top {
  flex-shrink: 0;
}

.screen__top--dark {
  background: #0a1628;
}

.screen__title {
  font-size: 28px;
  font-weight: 900;
  color: var(--color-text);
  padding: 12px var(--px) 4px;
  line-height: 1.2;
}

.screen__subtitle {
  font-size: 15px;
  color: var(--color-caption);
  padding: 0 var(--px) 20px;
  line-height: 1.5;
}

.screen-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 14px var(--px);
  gap: 12px;
}

.screen__top--dark .screen-header {
  padding-top: max(14px, env(safe-area-inset-top));
}

.screen-header__info {
  flex: 1;
  text-align: center;
}

.room-badge {
  display: inline-block;
  background: var(--color-primary);
  color: white;
  font-size: 15px;
  font-weight: 800;
  letter-spacing: 0.5px;
  padding: 4px 16px;
  border-radius: 100px;
}

.screen__top--dark .room-badge {
