/**
 * Housekeeping Report App
 * 4-screen SPA: Room Input → Camera → Report → Success
 */

// ── App State ──────────────────────────────────────────────
const state = {
  roomId: '',
  photos: [],        // Array of { blob, dataUrl, s3Url }
  voiceText: '',
  stream: null,      // MediaStream
  recognition: null, // SpeechRecognition
  isRecording: false,
};

// ── DOM Refs ────────────────────────────────────────────────
const screens = {
  room:    document.getElementById('screen-room'),
  camera:  document.getElementById('screen-camera'),
  report:  document.getElementById('screen-report'),
  success: document.getElementById('screen-success'),
};

// ── Screen Navigation ───────────────────────────────────────
function showScreen(name) {
  const next = screens[name];
  const current = document.querySelector('.screen--active');

  if (current && current !== next) {
    current.classList.remove('screen--active');
    current.classList.add('screen--exit');
    setTimeout(() => current.classList.remove('screen--exit'), 300);
  }

  next.classList.add('screen--active');

  // Lifecycle hooks
  if (name === 'camera') onEnterCamera();
  if (name === 'report') onEnterReport();
  if (name === 'success') onEnterSuccess();
  if (name === 'room')   onEnterRoom();
}

// ── Utilities ───────────────────────────────────────────────
function escapeHtml(text) {
  const d = document.createElement('div');
  d.textContent = text;
  return d.innerHTML;
}

let toastTimer = null;
function showToast(msg) {
  const el = document.getElementById('global-toast');
  el.textContent = msg;
  el.classList.remove('global-toast--hidden');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => el.classList.add('global-toast--hidden'), 2800);
}

function showFieldError(el, msg) {
  el.textContent = msg;
  el.classList.remove('toast--hidden');
  setTimeout(() => el.classList.add('toast--hidden'), 3000);
}

// ============================================================
// SCREEN 1 – ROOM INPUT
// ============================================================
const roomInput  = document.getElementById('room-input');
const btnRoomNext = document.getElementById('btn-room-next');
const roomError  = document.getElementById('room-error');

roomInput.addEventListener('input', () => {
  const hasValue = roomInput.value.trim().length > 0;
  btnRoomNext.disabled = !hasValue;
  btnRoomNext.classList.toggle('btn--disabled', !hasValue);
});

btnRoomNext.addEventListener('click', () => {
  const val = roomInput.value.trim();
  if (!val) {
    showFieldError(roomError, 'Vui lòng nhập mã phòng');
    return;
  }
  state.roomId = val.toUpperCase();
  showScreen('camera');
});

// Allow Enter key
roomInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter' && roomInput.value.trim()) {
    btnRoomNext.click();
  }
});

function onEnterRoom() {
  roomInput.value = '';
  btnRoomNext.disabled = true;
  btnRoomNext.classList.add('btn--disabled');
  roomError.classList.add('toast--hidden');
  setTimeout(() => roomInput.focus(), 350);
}

// ============================================================
// SCREEN 2 – CAMERA
// ============================================================
const cameraVideo   = document.getElementById('camera-video');
const cameraCanvas  = document.getElementById('camera-canvas');
const cameraOverlay = document.getElementById('camera-overlay');
const shutterBtn    = document.getElementById('shutter-btn');
const thumbnailRow  = document.getElementById('thumbnail-row');
const photoCounter  = document.getElementById('photo-counter');
const btnCameraNext = document.getElementById('btn-camera-next');
const cameraHint    = document.getElementById('camera-hint');
const cameraBadge   = document.getElementById('camera-room-badge');

document.getElementById('btn-camera-back').addEventListener('click', () => {
  stopCamera();
  showScreen('room');
});

async function onEnterCamera() {
  state.photos = [];
  cameraBadge.textContent = `PHÒNG ${state.roomId}`;
  renderThumbnails();
  updateCameraUI();
  await startCamera();
}

async function startCamera() {
  cameraOverlay.classList.remove('camera-overlay--hidden');
  document.querySelector('.camera-overlay__text').textContent = 'Đang khởi động camera...';

  try {
    state.stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: { ideal: 'environment' }, width: { ideal: 1280 }, height: { ideal: 720 } },
      audio: false,
    });
    cameraVideo.srcObject = state.stream;
    cameraVideo.onloadedmetadata = () => {
      cameraOverlay.classList.add('camera-overlay--hidden');
    };
  } catch (err) {
    document.querySelector('.camera-overlay__icon').textContent = '🚫';
    document.querySelector('.camera-overlay__text').textContent =
      'Không thể truy cập camera. Vui lòng cấp quyền.';
  }
}

function stopCamera() {
  if (state.stream) {
    state.stream.getTracks().forEach(t => t.stop());
    state.stream = null;
  }
  cameraVideo.srcObject = null;
}

shutterBtn.addEventListener('click', () => {
  if (state.photos.length >= 3) return;
  capturePhoto();
});

function capturePhoto() {
  const video = cameraVideo;
  const canvas = cameraCanvas;
  canvas.width = video.videoWidth || 640;
  canvas.height = video.videoHeight || 480;
  const ctx = canvas.getContext('2d');
  ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

  canvas.toBlob((blob) => {
    const dataUrl = canvas.toDataURL('image/jpeg', 0.85);
    state.photos.push({ blob, dataUrl, s3Url: null });
    renderThumbnails();
    updateCameraUI();
    // Flash feedback
    cameraOverlay.style.background = 'rgba(255,255,255,0.3)';
    cameraOverlay.style.opacity = '1';
    setTimeout(() => {
      cameraOverlay.style.background = '';
      cameraOverlay.style.opacity = '';
    }, 120);
    // Auto-navigate at 3 photos
    if (state.photos.length >= 3) {
      setTimeout(() => showScreen('report'), 400);
    }
  }, 'image/jpeg', 0.85);
}

function renderThumbnails() {
  thumbnailRow.innerHTML = state.photos.map((p, i) => `
    <div class="thumbnail">
      <img src="${p.dataUrl}" alt="Ảnh ${i + 1}">
      <button class="thumbnail__delete" data-index="${i}" aria-label="Xóa ảnh ${i + 1}">✕</button>
    </div>
  `).join('');

  thumbnailRow.querySelectorAll('.thumbnail__delete').forEach(btn => {
    btn.addEventListener('click', () => {
      const idx = parseInt(btn.dataset.index, 10);
      state.photos.splice(idx, 1);
      renderThumbnails();
      updateCameraUI();
    });
  });
}

function updateCameraUI() {
  const count = state.photos.length;
  photoCounter.textContent = `${count} / 3`;

  const canContinue = count >= 1;
  btnCameraNext.disabled = !canContinue;
  btnCameraNext.classList.toggle('btn--disabled', !canContinue);

  if (count === 0) {
    cameraHint.textContent = 'Chụp ít nhất 1 ảnh để tiếp tục';
    shutterBtn.style.opacity = '1';
  } else if (count < 3) {
    cameraHint.textContent = `${3 - count} ảnh nữa (hoặc nhấn Tiếp tục)`;
    shutterBtn.style.opacity = '1';
  } else {
    cameraHint.textContent = 'Đã đủ 3 ảnh';
    shutterBtn.style.opacity = '0.4';
  }
}

btnCameraNext.addEventListener('click', () => {
  if (state.photos.length >= 1) showScreen('report');
});

// ============================================================
// SCREEN 3 – ROOM REPORT
// ============================================================
const micBtn       = document.getElementById('mic-btn');
const micStatus    = document.getElementById('mic-status');
const voiceTextarea = document.getElementById('voice-textarea');
const reportBadge  = document.getElementById('report-room-badge');
const reportPhotos = document.getElementById('report-photos');
const btnSubmit    = document.getElementById('btn-submit');
const btnSubmitText = document.getElementById('btn-submit-text');
const btnSubmitSpinner = document.getElementById('btn-submit-spinner');
const reportError  = document.getElementById('report-error');

document.getElementById('btn-report-back').addEventListener('click', () => {
  stopRecording();
  showScreen('camera');
  // re-enter camera
  onEnterCamera();
});

function onEnterReport() {
  reportBadge.textContent = `PHÒNG ${state.roomId}`;
  voiceTextarea.value = '';
  state.voiceText = '';
  stopRecording();
  renderReportPhotos();
  reportError.classList.add('toast--hidden');
  resetSubmitBtn();
}

function renderReportPhotos() {
